// C solution (uses naive DP for LCS – acceptable for the given limits)
#include <bits/stdc++.h>
using namespace std;
int lcs_len(const string &a, const string &b){
    int n=a.size(), m=b.size();
    vector<int> dp(m+1,0), ndp(m+1,0);
    int best=0;
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            if(a[i-1]==b[j-1]) ndp[j]=dp[j-1]+1;
            else ndp[j]=0;
            best=max(best, ndp[j]);
        }
        swap(dp, ndp);
    }
    return best;
}
struct DSU{vector<int> p, r;DSU(int n):p(n),r(n,0){iota(p.begin(),p.end(),0);}int find(int x){return p[x]==x?x:p[x]=find(p[x]);}bool unite(int a,int b){a=find(a);b=find(b);if(a==b) return false; if(r[a]<r[b]) swap(a,b); p[b]=a; if(r[a]==r[b]) r[a]++; return true;}};
int main(){ios::sync_with_stdio(false);cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0; while(T--){int N;cin>>N;vector<string> s(N);for(int i=0;i<N;i++)cin>>s[i];
        struct Edge{int u,v,w;};
        vector<Edge> edges; edges.reserve(N*(N-1)/2);
        for(int i=0;i<N;i++) for(int j=i+1;j<N;j++) edges.push_back({i,j,lcs_len(s[i],s[j])});
        sort(edges.begin(), edges.end(), [](const Edge&a,const Edge&b){return a.w>b.w;});
        DSU dsu(N); long long ans=0; int taken=0;
        for(const auto &e:edges){if(dsu.unite(e.u,e.v)){ans+=e.w; if(++taken==N-1) break;}}
        cout<<ans<<"\n";
    }
    return 0; }

